import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const s = {
  nav: { background: '#1a1a2e', padding: '0 2rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: '60px', borderBottom: '1px solid #2a2a4a' },
  logo: { color: '#7c6af7', fontWeight: 700, fontSize: '1.4rem', textDecoration: 'none' },
  links: { display: 'flex', gap: '1.5rem', alignItems: 'center' },
  link: { color: '#ccc', textDecoration: 'none', fontSize: '0.95rem' },
  btn: { background: '#7c6af7', color: '#fff', border: 'none', padding: '0.4rem 1rem', borderRadius: '6px', cursor: 'pointer', fontSize: '0.9rem' },
  xp: { color: '#f7c948', fontSize: '0.85rem', fontWeight: 600 },
};

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    window.location.href = '/login';
  };

  return (
    <nav style={s.nav}>
      <Link to="/" style={s.logo}>⚡ CodeForge</Link>
      <div style={s.links}>
        {user ? (
          <>
            <Link to="/" style={s.link}>Courses</Link>
            <Link to="/leaderboard" style={s.link}>Leaderboard</Link>
            <Link to="/profile" style={s.link}>Profile</Link>
            <span style={s.xp}>⭐ {user.xp} XP</span>
            <button style={s.btn} onClick={handleLogout}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={s.link}>Login</Link>
            <Link to="/register" style={{ ...s.btn, textDecoration: 'none', padding: '0.4rem 1rem' }}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}
